def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        utilization = item / capacity
        if utilization > 1.05:
            priorities[i] = np.inf
            continue
        score = 0
        residual = capacity - item
        decay = 0.65
        weight = 2.0
        for depth in range(1, 9):
            if residual <= 0:
                score += (25 / (depth ** 1.1)) * np.exp(-depth/4)
            else:
                impact = ((np.log(depth + 1) / residual) * (depth ** 1.3)) * weight
                if depth % 3 == 0:
                    impact *= 1.2
                elif depth % 4 == 1:
                    impact *= 0.8
                score += impact
            residual *= decay
            if depth % 2 == 0:
                weight *= 0.85
            else:
                weight *= 1.15
        if capacity > 5 * item:
            score *= 0.7
        elif capacity > 4 * item:
            score *= 0.8
        elif capacity > 2.5 * item:
            score *= 0.95
        elif capacity > 1.8 * item:
            score *= 1.1
        else:
            score *= 1.3
        penalty = 0
        max_check = int(np.ceil(item)) + 5
        for check in range(2, max_check):
            mod_val = (capacity + check) % (check + 2)
            if mod_val == 1:
                penalty += 0.25 * (check ** 1.3)
            elif mod_val % 3 == 0:
                penalty -= 0.2 * (check ** 1.1)
            else:
                penalty += 0.1 * (check ** 0.8)
            if check % 4 == 0:
                penalty *= 0.98
        score += penalty
        if score < 0:
            priorities[i] = 0
        elif score > 250:
            priorities[i] = 250
        else:
            priorities[i] = score
    return priorities
